code.C++:
#include <iostream>
#include <vector>
using namespace std;

int main() {
    int t;
    cin >> t;

    while (t--) {
        int n;
        cin >> n;
        vector<int> arr(n);
        int sum = 0; 
        for (int i = 0; i < n; i++) {
            cin >> arr[i];
            if (arr[i] % 3 == 0)
                sum += arr[i];
        }

        cout << sum << endl;
    }

    return 0;
}

